// FILE: packages/app/src/lib/actions/swipeable.ts
import { SWIPE_THRESHOLD, DEADZONE_RATIO } from '$lib/constants.js';
import { appDimensions } from '$lib/state/appDimensions';

interface SwipeableParams {
	providers: readonly string[];
	getProvider: () => string;
	onSwitch: (dir: 1 | -1) => void;
	isEnabled?: () => boolean;
}

export function swipeable(node: HTMLElement, params: SwipeableParams) {
	const { providers, getProvider, onSwitch, isEnabled } = params;

	let swipeStartX = 0;
	let swipeStartY = 0;
	let swipeAxis: 'none' | 'horizontal' | 'vertical' = 'none';
	let isSwiping = false;
	let swipeAnimating = false;

	function getAdjacentProvider(dir: 1 | -1): string | null {
		const idx = providers.indexOf(getProvider());
		const newIdx = idx + dir;
		if (newIdx < 0 || newIdx >= providers.length) return null;
		return providers[newIdx];
	}

	function handleTouchStart(e: TouchEvent) {
		if (isEnabled && !isEnabled()) return;
		if (swipeAnimating) return;
		swipeStartX = e.touches[0].clientX;
		swipeStartY = e.touches[0].clientY;
		swipeAxis = 'none';
		isSwiping = false;
	}

	function handleTouchMove(e: TouchEvent) {
		if (isEnabled && !isEnabled()) return;
		if (swipeAnimating) return;
		if (swipeAxis === 'vertical') return;

		const touch = e.touches[0];
		const dx = touch.clientX - swipeStartX;
		const dy = touch.clientY - swipeStartY;

		if (swipeAxis === 'none') {
			const deadzone = appDimensions.width * DEADZONE_RATIO;
			if (Math.abs(dx) < deadzone && Math.abs(dy) < deadzone) return;
			if (Math.abs(dy) > Math.abs(dx)) {
				swipeAxis = 'vertical';
				return;
			}
			swipeAxis = 'horizontal';
			isSwiping = true;
		}

		e.preventDefault();

		const dir: 1 | -1 = dx < 0 ? 1 : -1;
		const adjacent = getAdjacentProvider(dir);
		node.style.transition = 'none';
		node.style.transform = adjacent
			? `translateX(${dx}px)`
			: `translateX(${dx * 0.3}px)`;
	}

	function handleTouchEnd(e: TouchEvent) {
		if (swipeAxis !== 'horizontal' || !isSwiping) {
			swipeAxis = 'none';
			isSwiping = false;
			return;
		}

		const dx = e.changedTouches[0].clientX - swipeStartX;
		const dir: 1 | -1 = dx < 0 ? 1 : -1;
		const adjacent = getAdjacentProvider(dir);

		if (Math.abs(dx) > appDimensions.width * SWIPE_THRESHOLD && adjacent) {
			animateProviderSwitch(dir);
		} else {
			node.style.transition = 'transform 250ms ease-out';
			node.style.transform = 'translateX(0)';
			setTimeout(() => {
				node.style.transition = '';
				node.style.transform = '';
				isSwiping = false;
				swipeAxis = 'none';
			}, 250);
		}
	}

	function handleTouchCancel() {
		node.style.transition = '';
		node.style.transform = '';
		swipeAxis = 'none';
		isSwiping = false;
	}

	function animateProviderSwitch(direction: 1 | -1) {
		swipeAnimating = true;
		const vw = window.innerWidth;
		const slideOutTarget = direction > 0 ? -vw : vw;

		node.style.transition = 'transform 250ms ease-out';
		node.style.transform = `translateX(${slideOutTarget}px)`;

		setTimeout(() => {
			node.style.transition = 'none';
			node.style.transform = `translateX(${-slideOutTarget}px)`;
			onSwitch(direction);

			requestAnimationFrame(() => {
				node.style.transition = 'transform 250ms ease-out';
				node.style.transform = 'translateX(0)';
				setTimeout(() => {
					node.style.transition = '';
					node.style.transform = '';
					isSwiping = false;
					swipeAnimating = false;
					swipeAxis = 'none';
				}, 250);
			});
		}, 250);
	}

	node.addEventListener('touchstart', handleTouchStart);
	node.addEventListener('touchmove', handleTouchMove, { passive: false });
	node.addEventListener('touchend', handleTouchEnd);
	node.addEventListener('touchcancel', handleTouchCancel);

	return {
		destroy() {
			node.removeEventListener('touchstart', handleTouchStart);
			node.removeEventListener('touchmove', handleTouchMove);
			node.removeEventListener('touchend', handleTouchEnd);
			node.removeEventListener('touchcancel', handleTouchCancel);
		}
	};
}


// FILE: packages/app/src/lib/components/AliasSelector.svelte
<script lang="ts">
	import { videoListStore } from '$lib/stores/videoList.svelte.js';
	import { extractAlias, extractUniqueAliases } from '$lib/utils/alias.js';

	const aliasCounts = $derived.by(() => {
		const counts = new Map<string, number>();
		for (const v of videoListStore.videos) {
			const a = extractAlias(v.filename);
			counts.set(a, (counts.get(a) || 0) + 1);
		}
		return counts;
	});
	const aliases = $derived(
		extractUniqueAliases(videoListStore.videos).sort(
			(a, b) => (aliasCounts.get(b) || 0) - (aliasCounts.get(a) || 0)
		)
	);
	const selectedAliases = $derived(videoListStore.selectedAliases);

	let open = $state(false);
	let container = $state<HTMLElement | null>(null);

	function handleOutsideClick(e: MouseEvent) {
		if (container && !container.contains(e.target as Node)) {
			open = false;
		}
	}
</script>

<svelte:window onclick={handleOutsideClick} />

<div class="alias-selector" bind:this={container}>
	<button class="dropdown-toggle" onclick={() => (open = !open)}>
		{#if selectedAliases.size === 0}
			Select aliases...
		{:else}
			{selectedAliases.size} alias{selectedAliases.size === 1 ? '' : 'es'} selected
		{/if}
		<span class="arrow" class:open>{'\u25BC'}</span>
	</button>

	{#if open}
		<div class="dropdown-list">
			{#each aliases as alias}
				<button
					class="dropdown-item"
					class:selected={selectedAliases.has(alias)}
					onclick={() => videoListStore.toggleAlias(alias)}
				>
					<span class="check">{selectedAliases.has(alias) ? '\u2713' : ''}</span>
					{alias} <span class="count">({aliasCounts.get(alias) || 0})</span>
				</button>
			{/each}
		</div>
	{/if}

	{#if selectedAliases.size > 0}
		<div class="chips">
			{#each [...selectedAliases].sort() as alias}
				<span class="chip">
					{alias} <span class="count">({aliasCounts.get(alias) || 0})</span>
					<button class="chip-remove" onclick={() => videoListStore.removeAlias(alias)}
						>&times;</button
					>
				</span>
			{/each}
		</div>
	{/if}
</div>

<style>
	.alias-selector {
		width: 100%;
		position: relative;
	}

	.dropdown-toggle {
		width: 100%;
		padding: 8px 10px;
		background: transparent;
		border: 1px solid #555;
		border-radius: 6px;
		color: #aaa;
		font-size: 14px;
		cursor: pointer;
		text-align: left;
		display: flex;
		justify-content: space-between;
		align-items: center;
	}

	.dropdown-toggle:hover {
		background-color: rgba(255, 255, 255, 0.05);
		color: #fff;
	}

	.arrow {
		font-size: 10px;
		transition: transform 0.2s ease;
	}

	.arrow.open {
		transform: rotate(180deg);
	}

	.dropdown-list {
		position: absolute;
		top: 100%;
		left: 0;
		right: 0;
		max-height: 200px;
		overflow-y: auto;
		background-color: rgba(30, 30, 30, 0.95);
		border: 1px solid #555;
		border-radius: 6px;
		margin-top: 2px;
		z-index: 200;
	}

	.dropdown-item {
		width: 100%;
		padding: 6px 10px;
		background: transparent;
		border: none;
		color: #ccc;
		font-size: 13px;
		cursor: pointer;
		text-align: left;
		display: flex;
		align-items: center;
		gap: 6px;
	}

	.dropdown-item:hover {
		background-color: rgba(255, 255, 255, 0.1);
		color: #fff;
	}

	.dropdown-item.selected {
		color: #fff;
	}

	.check {
		width: 14px;
		font-size: 12px;
		color: #6c6;
	}

	.count {
		color: #888;
		font-size: 0.9em;
	}

	.chips {
		display: flex;
		flex-wrap: wrap;
		gap: 4px;
		padding: 6px 2px 2px;
	}

	.chip {
		display: inline-flex;
		align-items: center;
		gap: 4px;
		background-color: rgba(255, 255, 255, 0.1);
		border: 1px solid #555;
		border-radius: 12px;
		padding: 2px 8px;
		font-size: 12px;
		color: #ddd;
	}

	.chip-remove {
		background: none;
		border: none;
		color: #aaa;
		cursor: pointer;
		font-size: 14px;
		line-height: 1;
		padding: 0 2px;
	}

	.chip-remove:hover {
		color: #fff;
	}
</style>


// FILE: packages/app/src/lib/components/PlayerControls.svelte
<script lang="ts">
	import { playerStore } from '$lib/stores/player.svelte.js';
	import { videoListStore } from '$lib/stores/videoList.svelte.js';
	import { VIDEO_TYPE } from '$lib/constants.js';
	import {
		saveCurrentVideo,
		createEditedVideo,
		returnToOriginals
	} from '$lib/services/videoActions.js';
	import { addToList, removeFromList, isListProvider, extractIdentifier } from '$lib/services/list-api.js';

	let {
		isMuted,
		getCurrentTime,
		ontoggleMute
	}: {
		isMuted: boolean;
		getCurrentTime: () => number;
		ontoggleMute: () => void;
	} = $props();

	const video = $derived(playerStore.currentVideo);
	const segments = $derived(playerStore.segments);
	const isLive = $derived(video?.isLive === true);
	const isOriginal = $derived(video?.type === VIDEO_TYPE.ORIGINAL && !isLive);
	const isEdited = $derived(video?.type === VIDEO_TYPE.EDITED);
	const hasSegments = $derived(isOriginal && segments.length > 0);

	const provider = $derived(videoListStore.selectedProvider);
	const showListButton = $derived(isListProvider(provider) && !videoListStore.listLoading);
	const identifier = $derived(video ? extractIdentifier(video.filename) : '');
	const isInList = $derived(videoListStore.listIdentifiers.has(identifier));

	function handleMuteOrUndo() {
		if (hasSegments) {
			playerStore.removeLastSegment();
		} else {
			ontoggleMute();
		}
	}

	function handleOkOrCut() {
		if (hasSegments) {
			void createEditedVideo();
		} else {
			saveCurrentVideo();
		}
	}

	function handleListToggle() {
		if (!identifier || !isListProvider(provider)) return;
		if (isInList) {
			videoListStore.removeListIdentifier(identifier);
			removeFromList(provider, identifier).catch(() => {
				videoListStore.addListIdentifier(identifier);
			});
		} else {
			videoListStore.addListIdentifier(identifier);
			addToList(provider, identifier).catch(() => {
				videoListStore.removeListIdentifier(identifier);
			});
		}
	}
</script>

{#if video}
	<div class="controls">
		<div class="buttons">
			<button onclick={handleMuteOrUndo}>
				{#if hasSegments}
					↪️
				{:else}
					{isMuted ? '🔇' : '🔊'}
				{/if}
			</button>

			{#if showListButton}
				<button class:list-add={!isInList} class:list-remove={isInList} onclick={handleListToggle}>
					{isInList ? '➖' : '➕'}
				</button>
			{/if}

			{#if isEdited}
				<button onclick={returnToOriginals}>🔄</button>
			{/if}

			{#if isOriginal}
				<button onclick={handleOkOrCut} disabled={hasSegments && segments.length % 2 !== 0}>
					{hasSegments ? '✂️' : '✅'}
				</button>
				<button onclick={() => playerStore.addSegment(getCurrentTime())}>📍</button>
			{/if}
		</div>
	</div>
{/if}

<style>
	.controls {
		display: flex;
		align-items: center;
	}

	.buttons {
		display: flex;
		gap: 10px;
	}

	button {
		padding: 12px 18px;
		font-size: 36px;
		min-width: 70px;
		background-color: rgba(0, 0, 0, 0.6);
		color: white;
		border: 1px solid white;
		border-radius: 8px;
		cursor: pointer;
		line-height: 1;
		text-align: center;
	}

	@media (hover: hover) and (pointer: fine) {
		button:not(:disabled):hover {
			background-color: #ff5e3a;
			border-color: #ff5e3a;
		}
	}

	button:not(:disabled):active {
		background-color: #ff5e3a;
		border-color: #ff5e3a;
	}

	button:disabled {
		opacity: 0.4;
		cursor: not-allowed;
		background-color: rgba(0, 0, 0, 0.6);
		border-color: #888;
		color: #888;
	}

	button.list-add {
		border-color: #34c759;
	}

	button.list-remove {
		border-color: #ff5e3a;
	}
</style>


// FILE: packages/app/src/lib/components/PlayerOverlay.svelte
<script lang="ts">
	import { playerStore } from '$lib/stores/player.svelte.js';
	import { videoListStore } from '$lib/stores/videoList.svelte.js';
	import { VIDEO_TYPE } from '$lib/constants.js';
	import { formatTimePrecise } from '$lib/utils/format.js';
	import {
		saveCurrentVideo,
		createEditedVideo,
		returnToOriginals
	} from '$lib/services/videoActions.js';
	import { addToList, removeFromList, isListProvider, extractIdentifier } from '$lib/services/list-api.js';
	import type { PlayerOverlayState } from '$lib/engine/PlayerOverlayState.svelte.js';

	let {
		overlay,
		onseek,
		onseekdirect,
		ontoggleMute,
		getCurrentTime
	}: {
		overlay: PlayerOverlayState;
		onseek: (time: number) => void;
		onseekdirect: (time: number) => void;
		ontoggleMute: () => void;
		getCurrentTime: () => number;
	} = $props();

	const video = $derived(overlay.video);
	const currentTime = $derived(overlay.currentTime);
	const duration = $derived(overlay.duration);
	const seekableEnd = $derived(overlay.seekableEnd);
	const isMuted = $derived(overlay.isMuted);
	const isActive = $derived(overlay.isActive);
	const displayDuration = $derived(
		duration === Infinity && seekableEnd > 0 ? seekableEnd : duration
	);

	// Progress bar
	const effectiveDuration = $derived(displayDuration === Infinity ? 0 : isNaN(displayDuration) ? 0 : displayDuration);
	const percentage = $derived(effectiveDuration > 0 ? (currentTime / effectiveDuration) * 100 : 0);
	const timeText = $derived(
		`${formatTimePrecise(currentTime)} / ${formatTimePrecise(effectiveDuration)}`
	);

	// Controls
	const segments = $derived(isActive ? playerStore.segments : []);
	const isLive = $derived(video?.isLive === true);
	const isOriginal = $derived(video?.type === VIDEO_TYPE.ORIGINAL && !isLive);
	const isEdited = $derived(video?.type === VIDEO_TYPE.EDITED);
	const hasSegments = $derived(isOriginal && segments.length > 0);

	const provider = $derived(videoListStore.selectedProvider);
	const showListButton = $derived(isActive && isListProvider(provider) && !videoListStore.listLoading);
	const identifier = $derived(video ? extractIdentifier(video.filename) : '');
	const isInList = $derived(videoListStore.listIdentifiers.has(identifier));

	// Progress bar scrubbing
	let progressBar = $state<HTMLElement | null>(null);
	let isScrubbing = $state(false);
	let cachedRect: DOMRect | null = null;
	let lastScrubTime = 0;
	let rafId = 0;
	let pendingScrubX = 0;

	function calcTimeFromX(clientX: number): number {
		if (!cachedRect || effectiveDuration <= 0) return 0;
		const position = Math.max(0, Math.min(clientX - cachedRect.left, cachedRect.width));
		return effectiveDuration * (position / cachedRect.width);
	}

	function onPointerDown(e: PointerEvent) {
		if (!isActive) return;
		isScrubbing = true;
		cachedRect = progressBar!.getBoundingClientRect();
		const time = calcTimeFromX(e.clientX);
		onseek(time);
		window.addEventListener('pointermove', onPointerMove);
		window.addEventListener('pointerup', onPointerUp);
	}

	function onPointerMove(e: PointerEvent) {
		if (!isScrubbing) return;
		pendingScrubX = e.clientX;
		if (!rafId) {
			rafId = requestAnimationFrame(flushScrub);
		}
	}

	function flushScrub() {
		rafId = 0;
		if (!isScrubbing) return;
		const time = calcTimeFromX(pendingScrubX);
		onseekdirect(time);
		lastScrubTime = time;
	}

	function onPointerUp() {
		if (rafId) {
			cancelAnimationFrame(rafId);
			rafId = 0;
		}
		if (isScrubbing && lastScrubTime > 0) {
			onseek(lastScrubTime);
		}
		isScrubbing = false;
		lastScrubTime = 0;
		cachedRect = null;
		window.removeEventListener('pointermove', onPointerMove);
		window.removeEventListener('pointerup', onPointerUp);
	}

	// Control handlers
	function handleMuteOrUndo() {
		if (hasSegments) {
			playerStore.removeLastSegment();
		} else {
			ontoggleMute();
		}
	}

	function handleOkOrCut() {
		if (hasSegments) {
			void createEditedVideo();
		} else {
			saveCurrentVideo();
		}
	}

	function handleListToggle() {
		if (!identifier || !isListProvider(provider)) return;
		if (isInList) {
			videoListStore.removeListIdentifier(identifier);
			removeFromList(provider, identifier).catch(() => {
				videoListStore.addListIdentifier(identifier);
			});
		} else {
			videoListStore.addListIdentifier(identifier);
			addToList(provider, identifier).catch(() => {
				videoListStore.removeListIdentifier(identifier);
			});
		}
	}
</script>

<div class="overlay-top-bar" class:ui-visible={playerStore.isUiVisible && !!video}>
	{#if video}
		<div class="streamer-name">{video.filename}</div>

		<div class="time-display-container">
			<span class="time-display">{timeText}</span>
		</div>

		<div
			class="progress-bar"
			role="slider"
			aria-valuenow={currentTime}
			aria-valuemin={0}
			aria-valuemax={effectiveDuration}
			tabindex="-1"
			bind:this={progressBar}
			onpointerdown={onPointerDown}
		>
			<div class="progress-fill" style:width="{percentage}%"></div>

			{#if effectiveDuration > 0}
				{#each segments as point}
					<div class="segment-marker" style:left="{(point / effectiveDuration) * 100}%"></div>
				{/each}
			{/if}

			<div class="segment-text-container">
				{#each { length: Math.ceil(segments.length / 2) } as _, i}
					<div class="segment-row">
						<span>start: {formatTimePrecise(segments[i * 2])}</span>
						{#if segments[i * 2 + 1] !== undefined}
							<span>end: {formatTimePrecise(segments[i * 2 + 1])}</span>
						{/if}
					</div>
				{/each}
			</div>
		</div>

		<div class="controls">
			<div class="buttons">
				<button onclick={handleMuteOrUndo}>
					{#if hasSegments}
						↪️
					{:else}
						{isMuted ? '🔇' : '🔊'}
					{/if}
				</button>

				{#if showListButton}
					<button class:list-add={!isInList} class:list-remove={isInList} onclick={handleListToggle}>
						{isInList ? '➖' : '➕'}
					</button>
				{/if}

				{#if isEdited}
					<button onclick={returnToOriginals}>🔄</button>
				{/if}

				{#if isOriginal}
					<button onclick={handleOkOrCut} disabled={hasSegments && segments.length % 2 !== 0}>
						{hasSegments ? '✂️' : '✅'}
					</button>
					<button onclick={() => playerStore.addSegment(getCurrentTime())}>📍</button>
				{/if}
			</div>
		</div>
	{/if}
</div>

<style>
	.overlay-top-bar {
		position: absolute;
		top: 0;
		left: 0;
		width: 100%;
		padding: calc(env(safe-area-inset-top, 0px) + 15px) 15px 15px 15px;
		box-sizing: border-box;
		background: linear-gradient(to bottom, rgba(0, 0, 0, 0.7), rgba(0, 0, 0, 0));
		z-index: 20;
		transition: opacity 0.3s ease;
		opacity: 0;
		pointer-events: none;
	}

	.overlay-top-bar.ui-visible {
		opacity: 1;
		pointer-events: auto;
	}

	.streamer-name {
		font-size: 1.2em;
		font-weight: bold;
		text-shadow: 1px 1px 2px black;
		margin-bottom: 10px;
		word-break: break-all;
	}

	.time-display-container {
		text-align: center;
		margin-bottom: 8px;
	}

	.time-display {
		display: inline-block;
		background-color: rgba(0, 0, 0, 0.5);
		padding: 4px 12px;
		border-radius: 6px;
		font-family: 'Courier New', Courier, monospace;
