	class:visible={isVisible}
	class:swipe-active={gesture.isSwiping}
	class:swipe-animating={gesture.swipeAnimating}
	style:transform={gesture.isSwiping || gesture.swipeAnimating
		? `translateX(${gesture.swipeProgress * 100}%)`
