					class:active={activeProvider === id}
					style={activeProvider === id ? `border-color: ${PROVIDER_META[id].accent}; color: ${PROVIDER_META[id].accent}` : ''}
					onclick={() => switchProvider(id)}
				>
					{PROVIDER_META[id].label}
				</button>
			{/each}
		</nav>
		<div class="controls">
