import * as path from "path";
import { FileSystemManager } from "../../common/fileSystemManager.js";
import logger from "../../common/logger.js";
import { DiskSession } from "./diskSession.js";

export interface InitCommitResult {
    fileName: string;
    isQualityChange: boolean;
}

export class InitTracker {
    private currentMapUri: string | null = null;
    private segmentCount: number = 0;
    private readonly disk: DiskSession;

    constructor(disk: DiskSession) {
        this.disk = disk;
    }

    public needsUpdate(mapUri: string): boolean {
        return mapUri !== this.currentMapUri;
    }

    public incrementSegmentCount(): void {
        this.segmentCount++;
    }

    public get count(): number {
        return this.segmentCount;
    }

    public async commitInit(
        mapUri: string,
        downloadFn: () => Promise<import("../core/interfaces.js").SegmentFetchResult>,
    ): Promise<InitCommitResult | null> {
        const result = await downloadFn();
        if (!result.data) return null;
        const buffer = result.data;

        if (!await this.disk.materialize()) return null;

        const isQualityChange = this.currentMapUri !== null;
        const fileName = isQualityChange
            ? `init_${this.segmentCount}.mp4`
            : "init.mp4";

        const filePath = path.join(this.disk.dirPath, fileName);
        const ok = await FileSystemManager.writeFile(filePath, buffer as unknown as Uint8Array);
        if (!ok) {
            logger.warn(`[InitTracker] Write failed for ${fileName} — will retry`);
            return null;
        }

        this.currentMapUri = mapUri;
        return { fileName, isQualityChange };
    }
}


// FILE: packages/downloader/src/services/download/playlistManager.ts
import * as path from "path";
import { fixTargetDuration } from "shared";
import { FileSystemManager } from "../../common/fileSystemManager.js";
import logger from "../../common/logger.js";
import { DiskSession } from "./diskSession.js";

export interface SegmentInfo {
    remoteUrl: string;
    localName: string;
    metadata: string[];
    accurateDuration?: number;
    programDateTime?: string;
}

export type SegmentUrlResolver = (segmentLine: string) => string;

export interface PlaylistTimeline {
    edge: string | null;
    mediaSequence: number;
    firstProgramDateTime: string | null;
    lastProgramDateTime: string | null;
}

export class PlaylistManager {
    private readonly disk: DiskSession;
    private ignoredSegments: Set<string> = new Set();
    private seenRemoteUrls: Set<string> = new Set();
    private lastSegmentNumber: number = -1;
    public startSequence: number = 0;
    private pendingHeader: string[] | null = null;
    private pendingQualityChanges: string[] = [];
    private currentTargetDuration: number = 0;
    private _timeline: PlaylistTimeline = {
        edge: null,
        mediaSequence: 0,
        firstProgramDateTime: null,
        lastProgramDateTime: null,
    };
    private lastDownloadedPDT: string | null = null;
    private _edgeSwitchActive = false;

    public get timeline(): Readonly<PlaylistTimeline> {
        return this._timeline;
    }

    public onEdgeSwitch(oldEdge: string | null, newEdge: string): void {
        this._edgeSwitchActive = this.lastDownloadedPDT !== null;
        if (this._edgeSwitchActive) {
            logger.info(`[PlaylistManager] Edge switch ${oldEdge ?? "none"} → ${newEdge}, PDT dedup active (lastPDT=${this.lastDownloadedPDT})`);
        }
    }

    public shouldSkipByTimeline(segment: SegmentInfo): boolean {
        if (!this._edgeSwitchActive || !segment.programDateTime || !this.lastDownloadedPDT) {
            return false;
        }

        if (segment.programDateTime <= this.lastDownloadedPDT) {
            logger.info(`[PlaylistManager] EDGE-DEDUP skip segment=${segment.localName} pdt=${segment.programDateTime} ≤ lastPDT=${this.lastDownloadedPDT}`);
            return true;
        }

        const lastDate = new Date(this.lastDownloadedPDT).getTime();
        const segDate = new Date(segment.programDateTime).getTime();
        const gapMs = segDate - lastDate;
        if (gapMs > 4000) {
            logger.warn(`[PlaylistManager] EDGE-GAP ${(gapMs / 1000).toFixed(1)}s between lastPDT=${this.lastDownloadedPDT} and newPDT=${segment.programDateTime}`);
        }
        this._edgeSwitchActive = false;
        return false;
    }

    public recordDownloadedPDT(pdt: string | undefined): void {
        if (pdt) {
            this.lastDownloadedPDT = pdt;
        }
    }

    private get fullPlaylistPath(): string {
        return path.join(this.disk.dirPath, "playlist.m3u8");
    }

    constructor(disk: DiskSession) {
        this.disk = disk;
    }

    private getExtinfDuration(metadata: string[]): number {
        const extinf = metadata.find((l) => l.startsWith("#EXTINF:"));
        if (extinf) {
            const val = parseFloat(extinf.slice("#EXTINF:".length).replace(",", ""));
            if (!isNaN(val)) return val;
        }
        return 2;
    }

    public addIgnoredSegment(segmentName: string): void {
        this.ignoredSegments.add(segmentName);
    }

    private async getExistingLocalSegments(): Promise<Set<string>> {
        if (!this.disk.materialized) return new Set();
        const content = await FileSystemManager.readFile(this.fullPlaylistPath);
        if (!content) {
            return new Set();
        }
        const lines = content.split("\n");
        const segments = new Set<string>();
        for (const line of lines) {
            const trimmed = line.trim();
            if (trimmed !== "" && !trimmed.startsWith("#")) {
                segments.add(trimmed);
            }
        }
        return segments;
    }

    public setEdge(variantUrl: string): void {
        const edgeMatch = variantUrl.match(/\/(b-hls-\d+)\//);
        if (edgeMatch) {
            this._timeline.edge = edgeMatch[1];
        }
    }

    public async identifyNewSegments(livePlaylistContent: string, urlResolver: SegmentUrlResolver): Promise<SegmentInfo[]> {
        const liveLines = livePlaylistContent.split("\n");
        const newSegments: SegmentInfo[] = [];

        for (const line of liveLines) {
            const trimmed = line.trim();
            if (trimmed.startsWith("#EXT-X-PROGRAM-DATE-TIME:")) {
                const pdt = trimmed.slice("#EXT-X-PROGRAM-DATE-TIME:".length);
                if (!this._timeline.firstProgramDateTime) {
                    this._timeline.firstProgramDateTime = pdt;
                }
                this._timeline.lastProgramDateTime = pdt;
            }
        }

        const fileExists = this.disk.materialized && await FileSystemManager.pathExists(this.fullPlaylistPath);

        if (!fileExists && !this.pendingHeader) {
            const headerLines = liveLines.filter(
                (line) =>
                    line.startsWith("#EXTM3U") ||
                    line.startsWith("#EXT-X-VERSION") ||
                    line.startsWith("#EXT-X-TARGETDURATION") ||
                    line.startsWith("#EXT-X-MEDIA-SEQUENCE") ||
                    line.startsWith("#EXT-X-MAP")
            );

            const hasMap = headerLines.some((l) => l.startsWith("#EXT-X-MAP"));
            this.pendingHeader = headerLines.map((l) => {
                if (hasMap && l.startsWith("#EXT-X-VERSION")) return "#EXT-X-VERSION:7";
                if (hasMap && l.startsWith("#EXT-X-MAP")) return '#EXT-X-MAP:URI="init.mp4"';
                return l;
            });

            const seqLine = headerLines.find((l) => l.startsWith("#EXT-X-MEDIA-SEQUENCE"));
            if (seqLine) {
                const seq = parseInt(seqLine.split(":")[1], 10);
                if (!isNaN(seq)) {
                    this.startSequence = seq;
                    this._timeline.mediaSequence = seq;
                }
            }
        }

        const existingSegments = await this.getExistingLocalSegments();

        let currentPDT: string | null = null;

        for (let i = 0; i < liveLines.length; i++) {
            const line = liveLines[i].trim();
            if (line === "") continue;

            if (line.startsWith("#EXT-X-PROGRAM-DATE-TIME:")) {
                currentPDT = line.slice("#EXT-X-PROGRAM-DATE-TIME:".length);
                continue;
            }

            if (line.startsWith("#")) {
                continue;
            }

            const remoteTsUrl = urlResolver(line);

            const tsNameWithQuery = remoteTsUrl.substring(remoteTsUrl.lastIndexOf("/") + 1);
            const localName = tsNameWithQuery.split("?")[0];

            if (!existingSegments.has(localName) && !this.ignoredSegments.has(localName) && !this.seenRemoteUrls.has(remoteTsUrl)) {
                const segmentMetadata: string[] = [];
                for (let j = i - 1; j >= 0; j--) {
                    const metaLine = liveLines[j].trim();
                    if (metaLine.startsWith("#EXTINF")) {
                        segmentMetadata.unshift(metaLine);
                    } else if (metaLine === "#EXT-X-DISCONTINUITY") {
                        segmentMetadata.unshift(metaLine);
                    } else if (metaLine.startsWith("#")) {
                        continue;
                    } else {
                        break;
                    }
                }
                this.seenRemoteUrls.add(remoteTsUrl);
                newSegments.push({ remoteUrl: remoteTsUrl, localName, metadata: segmentMetadata, programDateTime: currentPDT ?? undefined });
            }

            currentPDT = null;
        }

        return newSegments;
    }

    public bufferQualityChange(initSegmentName: string): void {
        this.pendingQualityChanges.push(initSegmentName);
        logger.debug(`[PlaylistManager] Buffered quality change: ${initSegmentName}`);
    }

    public async appendSegmentToPlaylist(segment: SegmentInfo): Promise<void> {
        const currentNumber = parseInt(segment.localName.replace(/\.ts$/, ""), 10);

        if (!isNaN(currentNumber) && this.lastSegmentNumber !== -1 && currentNumber !== this.lastSegmentNumber + 1) {
            await this.insertDiscontinuity();
        }

        if (!isNaN(currentNumber)) {
            this.lastSegmentNumber = currentNumber;
        }

        if (segment.accurateDuration !== undefined && segment.accurateDuration > 0) {
            const idx = segment.metadata.findIndex(l => l.startsWith("#EXTINF:"));
            if (idx !== -1) {
                segment.metadata[idx] = `#EXTINF:${segment.accurateDuration.toFixed(3)},`;
            }
        }

        const segDuration = segment.accurateDuration ?? this.getExtinfDuration(segment.metadata);
        const requiredTarget = Math.ceil(segDuration);

        if (this.pendingHeader) {
            this.currentTargetDuration = requiredTarget;
            const header = this.pendingHeader.map((l) =>
                l.startsWith("#EXT-X-TARGETDURATION") ? `#EXT-X-TARGETDURATION:${requiredTarget}` : l
            );

            let initialContent = header.map(l => l.trim()).join("\n") + "\n";

            for (const initName of this.pendingQualityChanges) {
                initialContent += `#EXT-X-DISCONTINUITY\n#EXT-X-MAP:URI="${initName}"\n`;
            }
            this.pendingQualityChanges = [];

            await FileSystemManager.writeFile(this.fullPlaylistPath, initialContent);
            this.pendingHeader = null;
        } else if (this.pendingQualityChanges.length > 0) {
            for (const initName of this.pendingQualityChanges) {
                const tag = `#EXT-X-DISCONTINUITY\n#EXT-X-MAP:URI="${initName}"\n`;
                await FileSystemManager.appendFile(this.fullPlaylistPath, tag);
            }
            this.pendingQualityChanges = [];
        }

        if (requiredTarget > this.currentTargetDuration) {
            const content = await FileSystemManager.readFile(this.fullPlaylistPath);
            if (content) {
                const updated = content.replace(
                    /^#EXT-X-TARGETDURATION:\d+$/m,
                    `#EXT-X-TARGETDURATION:${requiredTarget}`
                );
                await FileSystemManager.writeFile(this.fullPlaylistPath, updated);
                this.currentTargetDuration = requiredTarget;
            }
        }

        const entry = [...segment.metadata, segment.localName].join("\n") + "\n";
        await FileSystemManager.appendFile(this.fullPlaylistPath, entry);
    }

    private async insertDiscontinuity(): Promise<void> {
        const tag = "#EXT-X-DISCONTINUITY\n";
        await FileSystemManager.appendFile(this.fullPlaylistPath, tag);
        logger.debug(`[PlaylistManager] Inserted discontinuity tag.`);
    }

    public async finalizePlaylist(): Promise<void> {
        logger.info(`Finalizing playlist: ${this.fullPlaylistPath}`);
        const endTag = "#EXT-X-ENDLIST\n";
        await FileSystemManager.appendFile(this.fullPlaylistPath, endTag);

        const content = await FileSystemManager.readFile(this.fullPlaylistPath);
        if (content) {
            const { content: fixed, wasFixed } = fixTargetDuration(content);
            if (wasFixed) {
                await FileSystemManager.writeFile(this.fullPlaylistPath, fixed);
                logger.info(`[PlaylistManager] Fixed TARGETDURATION in ${this.fullPlaylistPath}`);
            }
        }
    }
}


// FILE: packages/downloader/src/services/download/streamDownloader.ts
import * as timersPromises from "timers/promises";
import * as path from "path";
import * as fs from "fs/promises";

import logger from "../../common/logger.js";
import { DownloadHandle } from "../state/downloadsManager.js";
import { FileSystemManager } from "../../common/fileSystemManager.js";
import type { PlaylistManager } from "./playlistManager.js";
import type { InitTracker } from "./initTracker.js";
import type { DiskSession } from "./diskSession.js";
import { IDownloadSession, IStreamProvider } from "../core/interfaces.js";
import { resolveSegmentUrl } from "../core/downloadUtils.js";
import { STALE_STREAM_TIMEOUT_MS, QUALITY_CHECK_INTERVAL_MS, HEARTBEAT_INTERVAL_MS, NO_NEW_SEGMENTS_SLEEP_MS, INIT_RETRY_SLEEP_MS, EDGE_RECOVERY_SLEEP_MS, CDN_FETCH_TIMEOUT_MS } from "../../common/timing.js";

export type ExitReason = "aborted" | "segment-failed" | "stale-timeout" | "fetch-failed";

export interface DownloadResult {
    segmentCount: number;
    aborted: boolean;
    exitReason: ExitReason;
    lastLiveUrl: string | null;
}

export class StreamDownloader {
    private handle: DownloadHandle;
    private provider: IStreamProvider;
    private _aborted = false;
    private rejectedCount = 0;

    constructor(handle: DownloadHandle, provider: IStreamProvider) {
        this.handle = handle;
        this.provider = provider;
    }

    public abort(): void {
        this._aborted = true;
    }

    public async run(
        masterUrl: string,
        playlistManager: PlaylistManager,
        initTracker: InitTracker,
        disk: DiskSession,
    ): Promise<DownloadResult> {
        const alias = this.handle.state?.alias ?? "unknown";
        const liveUrl = await this.provider.parseMasterPlaylist(masterUrl);

        if (!liveUrl) {
            logger.info(`[StreamDownloader] EARLY-EXIT ${alias} reason=parseMasterPlaylist-failed`);
            return { segmentCount: 0, aborted: false, exitReason: "fetch-failed", lastLiveUrl: null };
        }

        this.handle.update({ liveUrl });

        const edgeMatch = liveUrl.match(/\/(b-hls-\d+)\//);
        const edge = edgeMatch ? edgeMatch[1] : "unknown";
        logger.info(`[StreamDownloader] START ${alias} edge=${edge} variant=${liveUrl.split("?")[0]}`);

        let session = this.provider.createDownloadSession();
        playlistManager.setEdge(liveUrl);

        return await this.downloadLoop(alias, masterUrl, liveUrl, session, playlistManager, initTracker, disk);
    }

    private async checkForQualityUpgrade(
        alias: string,
        masterUrl: string,
        currentLiveUrl: string,
    ): Promise<string | null> {
        const betterUrl = await this.provider.parseMasterPlaylist(masterUrl);
        if (!betterUrl) {
            logger.debug(`[StreamDownloader] ${alias} quality check: master playlist unavailable`);
            return null;
        }

        const normalize = (url: string) =>
            url.split("?")[0].replace(/doppiocdn\.(org|com|net)/g, "doppiocdn._");

        if (normalize(betterUrl) === normalize(currentLiveUrl)) {
            logger.debug(`[StreamDownloader] ${alias} quality check: no change`);
            return null;
        }
        return betterUrl;
    }

    private async downloadLoop(
        alias: string,
        masterUrl: string,
        initialLiveUrl: string,
        initialSession: IDownloadSession,
        playlistManager: PlaylistManager,
        initTracker: InitTracker,
        disk: DiskSession,
    ): Promise<DownloadResult> {
        let liveUrl = initialLiveUrl;
        let session = initialSession;
        let lastDownload = Date.now();
        let segmentFailed = false;
        let health: 'ok' | 'stale' = 'ok';
        let lastQualityCheck = Date.now();
        const staleTimeout = STALE_STREAM_TIMEOUT_MS;

        while (!this._aborted && Date.now() - lastDownload < staleTimeout) {
            if (health === 'ok' && Date.now() - lastDownload > HEARTBEAT_INTERVAL_MS) {
                health = 'stale';
                const staleSec = ((Date.now() - lastDownload) / 1000).toFixed(0);
                logger.warn(`[StreamDownloader] STALE ${alias} segments=${initTracker.count} staleSec=${staleSec}`);
            }

            if (Date.now() - lastQualityCheck > QUALITY_CHECK_INTERVAL_MS) {
                lastQualityCheck = Date.now();
                const betterUrl = await this.checkForQualityUpgrade(alias, masterUrl, liveUrl);
                if (betterUrl) {
                    logger.info(`[StreamDownloader] Quality upgrade for ${alias}: ${betterUrl.split("?")[0]}`);
                    liveUrl = betterUrl;
                    this.handle.update({ liveUrl });
                }
            }

            let content = await session.fetchPlaylist(liveUrl);
            if (!content) {
                const recovered = await this.provider.recoverVariant(this.handle.masterPlaylistUrl);
                if (!recovered) {
                    logger.info(`[StreamDownloader] ${alias} variant failed, no recovery available (segments=${initTracker.count} url=${liveUrl})`);
                    await timersPromises.setTimeout(EDGE_RECOVERY_SLEEP_MS);
                    continue;
                }

                const oldEdge = playlistManager.timeline.edge;
                const newEdgeMatch = recovered.match(/\/(b-hls-\d+)\//);
                const newEdge = newEdgeMatch ? newEdgeMatch[1] : null;

                if (newEdge && newEdge !== oldEdge) {
                    playlistManager.setEdge(recovered);
                    playlistManager.onEdgeSwitch(oldEdge, newEdge);
                    logger.info(`[StreamDownloader] ${alias} EDGE-SWITCH ${oldEdge ?? "none"} → ${newEdge} variant=${recovered.split("?")[0]}`);
                } else {
                    logger.info(`[StreamDownloader] ${alias} variant recovered (same edge) variant=${recovered.split("?")[0]}`);
                }

                liveUrl = recovered;
                this.handle.update({ liveUrl });
                session = this.provider.createDownloadSession();

                content = await session.fetchPlaylist(liveUrl);
                if (!content) {
                    logger.warn(`[StreamDownloader] ${alias} recovered variant also failed — retrying`);
                    await timersPromises.setTimeout(EDGE_RECOVERY_SLEEP_MS);
                    continue;
                }
            }

            const mapMatch = content.match(/#EXT-X-MAP:URI="([^"]+)"/);
            if (mapMatch) {
                const mapUri = mapMatch[1];
                if (initTracker.needsUpdate(mapUri)) {
                    const initUrl = resolveSegmentUrl(liveUrl, mapUri);
                    const result = await initTracker.commitInit(
                        mapUri,
                        () => session.fetchSegment(initUrl),
                    );

                    if (!result) {
                        logger.warn(`[StreamDownloader] ${alias} init segment failed — retrying`);
                        await timersPromises.setTimeout(INIT_RETRY_SLEEP_MS);
                        continue;
                    }

                    if (result.isQualityChange) {
                        playlistManager.bufferQualityChange(result.fileName);
                    }

                    logger.info(`[StreamDownloader] Downloaded init segment for ${alias} (${result.fileName})`);
                }
            }

            const segments = await playlistManager.identifyNewSegments(
                content,
                (line) => resolveSegmentUrl(liveUrl, line),
            );

            let downloadedThisIteration = false;

            for (const segment of segments) {
                if (playlistManager.shouldSkipByTimeline(segment)) {
                    continue;
                }

                const fetchResult = await session.fetchSegment(segment.remoteUrl);

                const baseName = segment.localName.replace(/\.\w+$/, "");
                if (!/^\d+$/.test(baseName)) {
                    segment.localName = `${playlistManager.startSequence + initTracker.count}.ts`;
                }

                if (!fetchResult.data) {
                    if (fetchResult.retryable) {
                        logger.warn(`[StreamDownloader] ${alias} segment skipped segment=${segment.localName}`);
                        playlistManager.addIgnoredSegment(segment.localName);
                        continue;
                    }
                    logger.warn(`[StreamDownloader] ${alias} segment download failed segment=${segment.localName} url=${segment.remoteUrl} — stopping`);
                    segmentFailed = true;
                    break;
                }
                const tsBuffer = fetchResult.data;

                if (!await disk.materialize()) {
                    logger.error(`[StreamDownloader] ${alias} disk materialization failed — stopping`);
                    segmentFailed = true;
                    break;
                }

                const segmentPath = path.join(disk.dirPath, segment.localName);
                const writeSuccess = await FileSystemManager.writeFile(segmentPath, tsBuffer as unknown as Uint8Array);
                if (!writeSuccess) {
                    logger.error(`[StreamDownloader] ${alias} disk write failed segment=${segmentPath} — stopping`);
                    segmentFailed = true;
                    break;
                }

                const result = await this.provider.validateSegment(segmentPath);
                if (!result.valid) {
                    await fs.unlink(segmentPath).catch(() => {});
                    playlistManager.addIgnoredSegment(segment.localName);
                    this.rejectedCount++;
                } else {
                    if (result.duration !== undefined) {
                        segment.accurateDuration = result.duration;
                    }
                    await playlistManager.appendSegmentToPlaylist(segment);
                    playlistManager.recordDownloadedPDT(segment.programDateTime);
                    if (health === 'stale') {
                        health = 'ok';
                        const staleSec = ((Date.now() - lastDownload) / 1000).toFixed(0);
                        logger.info(`[StreamDownloader] RECOVERED ${alias} segments=${initTracker.count} staleSec=${staleSec}`);
                    }
                    lastDownload = Date.now();
                    initTracker.incrementSegmentCount();
                    downloadedThisIteration = true;
                }
            }

            if (segmentFailed) break;

            if (!downloadedThisIteration) {
                await timersPromises.setTimeout(NO_NEW_SEGMENTS_SLEEP_MS);
            }
        }

        const staleSec = ((Date.now() - lastDownload) / 1000).toFixed(0);
        const staleTimedOut = Date.now() - lastDownload >= staleTimeout;
        let exitReason: ExitReason;
        if (this._aborted) {
            exitReason = "aborted";
        } else if (segmentFailed) {
            exitReason = "segment-failed";
        } else if (staleTimedOut) {
            exitReason = "stale-timeout";
        } else {
            exitReason = "fetch-failed";
        }
        const tl = playlistManager.timeline;
        const tlStr = tl.edge ? ` edge=${tl.edge} seq=${tl.mediaSequence} firstPDT=${tl.firstProgramDateTime ?? "none"} lastPDT=${tl.lastProgramDateTime ?? "none"}` : "";
        const rejStr = this.rejectedCount > 0 ? ` rejected=${this.rejectedCount}` : "";
        logger.info(`[StreamDownloader] LOOP-EXIT ${alias} reason=${exitReason} staleSec=${staleSec} segments=${initTracker.count}${rejStr}${disk.materialized ? ` dir=${path.basename(disk.dirPath)}` : ""}${tlStr}`);

        return { segmentCount: initTracker.count, aborted: this._aborted, exitReason, lastLiveUrl: liveUrl };
    }
}


// FILE: packages/downloader/src/services/download/streamSession.ts
import * as path from "path";
import * as timersPromises from "timers/promises";

import logger from "../../common/logger.js";
import { SESSION_RETRY_SLEEP_MS } from "../../common/timing.js";
import { DownloadHandle } from "../state/downloadsManager.js";
import { IStreamProvider, DownloadExitContext } from "../core/interfaces.js";
import { setupDownloadDir } from "../core/downloadUtils.js";
import { StreamDownloader, DownloadResult } from "./streamDownloader.js";
import { PlaylistManager } from "./playlistManager.js";
import { InitTracker } from "./initTracker.js";
import { DiskSession } from "./diskSession.js";

export interface SessionResult {
    totalSegments: number;
    aborted: boolean;
}

export class StreamSession {
    private readonly streamerId: string;
    private readonly alias: string;
    private readonly handle: DownloadHandle;
    private readonly provider: IStreamProvider;
    private _aborted = false;
    private activeDownloader: StreamDownloader | null = null;

    constructor(
        streamerId: string,
        alias: string,
        handle: DownloadHandle,
        provider: IStreamProvider,
    ) {
        this.streamerId = streamerId;
        this.alias = alias;
        this.handle = handle;
        this.provider = provider;
    }

    public abort(): void {
        this._aborted = true;
        this.activeDownloader?.abort();
    }

    public async run(initialMasterUrl: string): Promise<SessionResult> {
        const disk = new DiskSession(
            this.alias,
            this.handle,
            () => setupDownloadDir(this.provider.providerName, this.alias, new Date()),
        );
        const playlistManager = new PlaylistManager(disk);
        const initTracker = new InitTracker(disk);

        let masterUrl = initialMasterUrl;
        let totalSegments = 0;

        while (!this._aborted) {
            const downloader = new StreamDownloader(this.handle, this.provider);
            this.activeDownloader = downloader;
            const result = await downloader.run(masterUrl, playlistManager, initTracker, disk);
            this.activeDownloader = null;
            totalSegments += result.segmentCount;

            if (result.aborted) break;

            const context: DownloadExitContext = {
                streamerId: this.streamerId,
                exitReason: result.exitReason,
                lastMasterUrl: masterUrl,
                lastLiveUrl: result.lastLiveUrl,
            };

            const retryUrl = await this.provider.shouldRetry(context);
            if (!retryUrl) {
                logger.info(`[StreamSession] ${this.alias}: stream ended (reason=${result.exitReason}, segments=${totalSegments})`);
                break;
            }

            masterUrl = retryUrl;
            logger.info(`[StreamSession] ${this.alias}: retrying (reason=${result.exitReason}, newMaster=${masterUrl !== context.lastMasterUrl})`);
            await timersPromises.setTimeout(SESSION_RETRY_SLEEP_MS);
        }

        if (disk.materialized) {
            await playlistManager.finalizePlaylist();
            logger.info(`[StreamSession] ${this.alias}: finalized dir=${path.basename(disk.dirPath)} totalSegments=${totalSegments}`);
        }

        this.handle.remove();
        return { totalSegments, aborted: this._aborted };
    }
}


