            getRoot: () => document.getElementById('view-list'),
            rootMargin: SENTINEL_ROOT_MARGIN,
            onIntersect: () => { appState.searchState.loadNextPage(); },
            disabled: isLoading,
            generation: appState.ui.listViewGeneration
        }}></div>
    {/if}

