import type { ViewMode } from '../types.js';
import { getJson, setJson, remove } from '../services/storage.js';

const SESSION_KEY = 'session';

export interface SessionSnapshot {
    viewMode: ViewMode;
    viewStack: ViewMode[];
    activeGalleryId?: number;
    searchQuery?: string;
    searchPage?: number;
    favoritesPage?: number;
    listScroll?: number;
    favoritesScroll?: number;
}

export function saveSession(snapshot: SessionSnapshot): void {
    setJson(SESSION_KEY, snapshot);
}

export function loadSession(): SessionSnapshot | null {
    return getJson<SessionSnapshot | null>(SESSION_KEY, null);
}

export function clearSession(): void {
    remove(SESSION_KEY);
}


// FILE: gallery-app/src/lib/state/toast.svelte.ts
export class ToastState {
    items = $state<{ id: number; message: string }[]>([]);
    private nextId = 0;
    private timerIds = new Set<ReturnType<typeof setTimeout>>();

    show(message: string, duration = 2000) {
        const id = this.nextId++;
        this.items = [...this.items, { id, message }];
        const timerId = setTimeout(() => {
            this.timerIds.delete(timerId);
            this.items = this.items.filter(t => t.id !== id);
        }, duration);
        this.timerIds.add(timerId);
    }

    destroy() {
        for (const t of this.timerIds) clearTimeout(t);
        this.timerIds.clear();
        this.items = [];
    }
}


