import express from 'express';
import bodyParser from 'body-parser';
import cors from 'cors';
import https from 'https';
import fs from 'fs';
import os from 'os';
import path from 'path';
import * as u from './utils.js';
import { CONFIG } from './config.js';
import { socketService } from './socket.service.js';
import { queueManager } from './queue.manager.js';
import { runSync, getSyncStatus } from './sync.js';
import { runRemove, getRemoveStatus, gitCommit } from './remove.js';
import { loadManifest } from './manifest.js';
import { hitomi } from 'gallery-sources';

const app = express();

const FILTERS_PATH = path.resolve(import.meta.dirname, '..', '..', 'filters.txt');
const ARTISTS_PATH = path.resolve(import.meta.dirname, '..', '..', 'artists.txt');
const QUERIES_PATH = path.resolve(import.meta.dirname, '..', '..', 'queries.txt');

const logServerInfo = (port: number) => {
    const networkInterfaces = os.networkInterfaces();
    console.log(`Downloader (Queue Manager) running securely on port ${port}`);

    Object.keys(networkInterfaces).forEach((ifaceName) => {
        networkInterfaces[ifaceName]?.forEach((iface) => {
            if (iface.family === 'IPv4' && !iface.internal) {
                console.log(`Queue UI Access: https://${iface.address}:${port}`);
            }
        });
    });
    console.log(`Working Directory: ${CONFIG.WORKING_DIR}`);
};

// --- SSL LOAD ---
let server: https.Server;
try {
    const httpsOptions = {
        key: fs.readFileSync(CONFIG.SSL.KEY),
        cert: fs.readFileSync(CONFIG.SSL.CERT)
    };
    server = https.createServer(httpsOptions, app);
    console.log('SSL Certificates loaded successfully.');
} catch (e) {
    console.error('Could not load SSL certificates. Check config.ts paths.');
    process.exit(1);
}

// --- INIT SOCKET ---
socketService.init(server);

// --- MIDDLEWARE ---
app.use(cors());
app.use(bodyParser.json({ limit: '5mb' }));

// --- STATIC UI SERVING ---
app.use(express.static(path.join(u.findProjectRoot(), 'public')));

// --- ROUTES ---
app.get('/status', (_req, res) => {
    res.json(queueManager.getStatus());
});

app.post('/queue', (req, res) => {
    const rawUrls = (req.body.urls || '').split('\n').filter((u: string) => u.trim() !== '');
    queueManager.updateQueue(rawUrls);
    res.json({ status: 'ok' });
});

app.post('/immediate', (req, res) => {
    const rawUrls = (req.body.urls || '').split('\n').filter((u: string) => u.trim() !== '');
    if (rawUrls.length === 0) {
        res.json({ status: 'empty' });
        return;
    }
    queueManager.injectImmediate(rawUrls);
    res.json({ status: 'ok' });
});

app.post('/pause', (_req, res) => {
    queueManager.pause();
    res.json({ status: 'paused' });
});

app.post('/resume', (_req, res) => {
    queueManager.resume();
    res.json({ status: 'resumed' });
});

app.post('/cancel', (_req, res) => {
    queueManager.cancel();
    res.json({ status: 'stopped' });
});

// --- SYNC ROUTES ---
app.post('/sync', async (_req, res) => {
    res.json({ status: 'started' });
    runSync(FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH).catch(console.error);
});

app.get('/sync/status', (_req, res) => {
    res.json(getSyncStatus());
});

// --- REMOVE ROUTES ---
app.post('/remove', (req, res) => {
    const { file, line } = req.body;
    if (file !== 'artists' && file !== 'queries') {
        res.status(400).json({ error: 'file must be "artists" or "queries"' });
        return;
    }
    if (!line || typeof line !== 'string') {
        res.status(400).json({ error: 'line must be a non-empty string' });
        return;
    }
    res.json({ status: 'started' });
    runRemove(file, line.trim(), FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH).catch(console.error);
});

app.get('/remove/status', (_req, res) => {
    res.json(getRemoveStatus());
});

// --- ARTISTS ENDPOINTS ---
app.get('/artists', (_req, res) => {
    const manifest = loadManifest(FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH);
    const entries = manifest.artists.map(a => `${a.namespace}:${a.value}`);
    console.log(`[artists] GET /artists: ${entries.length} entries`);
    res.json(entries);
});

app.post('/artists/add', (req, res) => {
    const { line } = req.body;
    if (!line || typeof line !== 'string') {
        res.status(400).json({ error: 'line must be a non-empty string' });
        return;
    }

    const trimmed = line.trim();
    const colonIdx = trimmed.indexOf(':');
    if (colonIdx === -1) {
        res.status(400).json({ error: 'line must be namespace:value format' });
        return;
    }
    const ns = trimmed.slice(0, colonIdx);
    if (ns !== 'artist' && ns !== 'group') {
        res.status(400).json({ error: 'namespace must be artist or group' });
        return;
    }

    const content = fs.readFileSync(ARTISTS_PATH, 'utf-8');
    const lines = content.split('\n').map(l => l.trim());
    if (lines.includes(trimmed)) {
        console.log(`[artists] add ${trimmed}: already_exists`);
        res.json({ status: 'already_exists' });
        return;
    }

    const separator = content.endsWith('\n') ? '' : '\n';
    fs.appendFileSync(ARTISTS_PATH, `${separator}${trimmed}\n`);
    gitCommit(ARTISTS_PATH, `add ${trimmed} to artists.txt`);

    console.log(`[artists] added ${trimmed}`);
    res.json({ status: 'added' });
});

// --- QUERIES ENDPOINT (for frontend saved searches) ---
app.get('/queries', (_req, res) => {
    const manifest = loadManifest(FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH);
    res.json(manifest.queries.map(q => q.raw));
});

// --- FILE WATCH: auto-sync on manifest changes ---
function watchManifests() {
    let debounceTimer: ReturnType<typeof setTimeout> | null = null;

    const triggerSync = () => {
        if (debounceTimer) clearTimeout(debounceTimer);
        debounceTimer = setTimeout(() => {
            console.log('[watch] Manifest changed, triggering sync...');
            runSync(FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH).catch(console.error);
        }, 2000);
    };

    for (const filePath of [FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH]) {
        try {
            fs.watch(filePath, () => triggerSync());
            console.log(`[watch] Watching ${path.basename(filePath)}`);
        } catch {
            console.log(`[watch] Could not watch ${path.basename(filePath)} (file may not exist)`);
        }
    }
}

// --- POST-DOWNLOAD HOOKS ---
// Rejects galleries whose language doesn't match filters.txt.
// Hitomi's nozomi sometimes returns wrong-language IDs for an artist.
const GALLERY_ROOT = path.join(CONFIG.WORKING_DIR, hitomi.gallerySubdir);
const filterLanguage = loadManifest(FILTERS_PATH, ARTISTS_PATH, QUERIES_PATH).filters.language;

queueManager.setValidator((galleryId) => {
    const infoPath = path.join(GALLERY_ROOT, galleryId, hitomi.metadataFile);
    try {
        const info = JSON.parse(fs.readFileSync(infoPath, 'utf-8'));
        if (info.language !== filterLanguage) {
            return { valid: false, reason: `language "${info.language}" != "${filterLanguage}"` };
        }
        return { valid: true };
    } catch {
        return { valid: true };
    }
});

// Notify indexer after each successful download
const INDEXER_PORT = 11557;
queueManager.setOnComplete((galleryId) => {
    const req = https.request({
        hostname: 'localhost',
        port: INDEXER_PORT,
        path: `/index/${galleryId}`,
        method: 'POST',
        rejectUnauthorized: false,
    }, (res) => { res.resume(); });
    req.on('error', (err) => {
        console.log(`[index-notify] failed for ${galleryId}: ${err.message}`);
    });
    req.end();
});

// --- START ---
server.listen(CONFIG.PORT, '0.0.0.0', () => {
    logServerInfo(CONFIG.PORT);
    queueManager.restore();
    watchManifests();
});


// FILE: gallery-server/downloader/src/manifest-resolver.ts
/**
 * Manifest resolver: single owner of "what gallery IDs are wanted."
 *
 * Loads all three manifest files, resolves IDs from hitomi, applies
 * the filter policy (language + exclusions) from filters.txt.
 *
 * Consumers (sync, remove) call this — they own execution flow and
 * error policy, but NOT resolution logic.
 */

import { loadManifest, type Manifest } from './manifest.js';
import { resolveArtistEntry, resolveQuery, resolveTag } from './resolver.js';

function delay(ms: number): Promise<void> {
    return new Promise(r => setTimeout(r, ms));
}

/** Build a full query string: language + positive tokens + filter negatives. */
function buildMergedQuery(queryPositives: string, language: string, negatives: string[]): string {
    const parts = [`language:${language.replace(/ /g, '_')}`, queryPositives.trim()];
    for (const neg of negatives) {
        parts.push(`-${neg}`);
    }
    return parts.join(' ');
}

/** Subtract all filter negatives from an ID set. */
async function subtractNegatives(
    ids: Set<number>,
    negatives: string[],
    language: string,
    onExcluded?: (tag: string, removed: number, remaining: number) => void,
): Promise<string[]> {
    const errors: string[] = [];
    for (const tag of negatives) {
        const result = await resolveTag(tag, language);
        if (result.errors.length > 0) {
            errors.push(...result.errors);
        } else {
            const before = ids.size;
            for (const id of result.ids) ids.delete(id);
            onExcluded?.(tag, before - ids.size, ids.size);
        }
        await delay(100);
    }
    return errors;
}

export interface ResolutionResult {
    wantedIds: Set<number>;
    artistCount: number;
    queryCount: number;
    errors: string[];
}

export interface ResolutionCallbacks {
    onArtistResolved?: (resolved: number, total: number, idsSoFar: number) => void;
    onTagExcluded?: (tag: string, removed: number, remaining: number) => void;
    onQueryResolved?: (resolved: number, total: number, queryIds: number, totalIds: number) => void;
}

/**
 * Resolve the complete wanted ID set from all three manifest files.
 *
 * 1. Resolve all artist/group entries in the filter language
 * 2. Subtract ALL filter negatives from artist IDs
 * 3. Resolve all query entries with filter language + negatives merged in
 *
 * The caller decides error policy (sync continues, remove aborts).
 */
export async function resolveManifest(
    filtersPath: string,
    artistsPath: string,
    queriesPath: string,
    callbacks?: ResolutionCallbacks,
): Promise<ResolutionResult> {
    const manifest = loadManifest(filtersPath, artistsPath, queriesPath);
    const { language, negatives } = manifest.filters;
    const wantedIds = new Set<number>();
    const errors: string[] = [];

    // Phase 1: Resolve artist entries
    for (let i = 0; i < manifest.artists.length; i++) {
        const entry = manifest.artists[i];
        const result = await resolveArtistEntry(entry.namespace, entry.value, language);
        for (const id of result.ids) wantedIds.add(id);
        errors.push(...result.errors);
        callbacks?.onArtistResolved?.(i + 1, manifest.artists.length, wantedIds.size);
    }

    // Phase 2: Subtract all filter negatives from artist IDs
    const tagErrors = await subtractNegatives(
        wantedIds, negatives, language, callbacks?.onTagExcluded,
    );
    errors.push(...tagErrors);

    // Phase 3: Resolve query entries with filters merged in
    for (let i = 0; i < manifest.queries.length; i++) {
        const entry = manifest.queries[i];
        const mergedQuery = buildMergedQuery(entry.raw, language, negatives);
        const result = await resolveQuery(mergedQuery);
        for (const id of result.ids) wantedIds.add(id);
        errors.push(...result.errors);
        callbacks?.onQueryResolved?.(i + 1, manifest.queries.length, result.ids.size, wantedIds.size);
    }

    return {
        wantedIds,
        artistCount: manifest.artists.length,
        queryCount: manifest.queries.length,
        errors,
    };
}

/**
 * Resolve a single entry's IDs with filter policy applied.
 * Used by the remove endpoint to compute what a removed entry contributed.
 */
export async function resolveEntryWithFilters(
    manifest: Manifest,
    file: 'artists' | 'queries',
    line: string,
): Promise<{ ids: Set<number>; errors: string[] }> {
    const { language, negatives } = manifest.filters;
    const errors: string[] = [];

    if (file === 'artists') {
        const colonIdx = line.indexOf(':');
        if (colonIdx === -1) return { ids: new Set(), errors };

        const ns = line.slice(0, colonIdx);
        const val = line.slice(colonIdx + 1);
        const entry = manifest.artists.find(a => a.namespace === ns && a.value === val);
        if (!entry) return { ids: new Set(), errors };

        const result = await resolveArtistEntry(entry.namespace, entry.value, language);
        errors.push(...result.errors);

        const tagErrors = await subtractNegatives(result.ids, negatives, language);
        errors.push(...tagErrors);

        return { ids: result.ids, errors };
    } else {
        const mergedQuery = buildMergedQuery(line, language, negatives);
        const result = await resolveQuery(mergedQuery);
        return { ids: result.ids, errors: result.errors };
    }
}


// FILE: gallery-server/downloader/src/manifest.ts
/**
 * Manifest parser: reads filters.txt, artists.txt, and queries.txt.
 *
 * Owns parsing of all three files. Never writes to them.
 *
 * filters.txt — base filter policy (language + exclusions)
 * artists.txt — tracked creators (namespace:name)
 * queries.txt — specific positive tag searches
 */

import fs from 'fs';

export interface Filters {
    language: string;
    negatives: string[];  // e.g. ['tag:anthology', 'female:scat']
}

export interface ArtistEntry {
    namespace: string;   // 'artist' | 'group'
    value: string;       // e.g. 'mizuryu_kei'
}

export interface QueryEntry {
    raw: string;         // just positive tokens, e.g. 'female:cheating'
}

export interface Manifest {
    filters: Filters;
    artists: ArtistEntry[];
    queries: QueryEntry[];
}

function parseFiltersFile(filePath: string): Filters {
    let content: string;
    try {
        content = fs.readFileSync(filePath, 'utf-8');
    } catch {
        return { language: 'japanese', negatives: [] };
    }

    let language = 'japanese';
    const negatives: string[] = [];

    for (const raw of content.split('\n')) {
        const line = raw.trim();
        if (!line || line.startsWith('#')) continue;

        if (line.startsWith('language:')) {
            language = line.slice('language:'.length).replace(/_/g, ' ');
            continue;
        }

        if (line.startsWith('-')) {
            const token = line.slice(1);
            if (token.includes(':')) {
                negatives.push(token);
            }
        }
    }

    return { language, negatives };
}

function parseArtistsFile(filePath: string): ArtistEntry[] {
    let content: string;
    try {
        content = fs.readFileSync(filePath, 'utf-8');
    } catch {
        return [];
    }

    const entries: ArtistEntry[] = [];

    for (const raw of content.split('\n')) {
        const line = raw.trim();
        if (!line || line.startsWith('#')) continue;

        const colonIdx = line.indexOf(':');
        if (colonIdx === -1) continue;

        const namespace = line.slice(0, colonIdx);
        const value = line.slice(colonIdx + 1);

        if (namespace === 'artist' || namespace === 'group') {
            entries.push({ namespace, value });
        }
    }

    return entries;
}

function parseQueriesFile(filePath: string): QueryEntry[] {
    let content: string;
    try {
        content = fs.readFileSync(filePath, 'utf-8');
    } catch {
        return [];
    }

    const entries: QueryEntry[] = [];

    for (const raw of content.split('\n')) {
        const line = raw.trim();
        if (!line || line.startsWith('#')) continue;
        entries.push({ raw: line });
    }

    return entries;
}

export function loadManifest(filtersPath: string, artistsPath: string, queriesPath: string): Manifest {
    return {
        filters: parseFiltersFile(filtersPath),
        artists: parseArtistsFile(artistsPath),
        queries: parseQueriesFile(queriesPath),
    };
}


